import java.io.*;
import java.util.HashMap;
import java.util.Map;

public class DiskCache {
    private final String cacheDirectory;
    private Map<String, File> fileMap = new HashMap<>();

    public DiskCache(String directory) throws IOException {
        this.cacheDirectory = directory;
        File dir = new File(directory);
        if (!dir.exists()) {
            if (!dir.mkdirs()) {
                throw new IOException("Failed to create cache directory");
            }
        }
    }

    public void put(String key, Serializable value) throws IOException {
        File file = new File(cacheDirectory, key);
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(file))) {
            oos.writeObject(value);
        }
        fileMap.put(key, file);
    }

    public Object get(String key) throws IOException, ClassNotFoundException {
        File file = fileMap.get(key);
        if (file == null || !file.exists()) {
            return null;
        }
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(file))) {
            return ois.readObject();
        }
    }

    public void remove(String key) {
        File file = fileMap.remove(key);
        if (file != null && file.exists()) {
            file.delete();
        }
    }

    public void clear() throws IOException {
        for (File file : fileMap.values()) {
            file.delete();
        }
        fileMap.clear();
    }
}